class Solution:
    def uniquePathsWithObstacles(self, g: List[List[int]]) -> int:
        m, n = len(g), len(g[0])
        if g[0][0] or g[m - 1][n - 1]:
            return 0
        dp = [0] * n
        dp[0] = 1
        for i in range(m):
            for j in range(n):
                if g[i][j]:
                    dp[j] = 0
                elif j:
                    dp[j] += dp[j - 1]
        return dp[-1]

