int uniquePathsWithObstacles(int** g, int m, int n) {
    if (g[0][0] || g[m - 1][n - 1]) return 0;
    int dp[n];
    for (int j = 0; j < n; j++) dp[j] = 0;
    dp[0] = 1;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (g[i][j]) dp[j] = 0;
            else if (j) dp[j] += dp[j - 1];
        }
    }
    return dp[n - 1];
}
